function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return undefined;
}

function toStringSafe(v) {
  if (v == null) return '';
  if (typeof v === 'string') return v;
  if (typeof v === 'number' || typeof v === 'boolean') return String(v);
  try { return JSON.stringify(v); } catch { return String(v); }
}

const wh = $json.body ?? $json ?? {};

let image_count = Number(
  pickFirst(wh.image_count, wh.imageCount, wh.image_count_user, 3)
);
if (!Number.isFinite(image_count) || image_count < 1) image_count = 3;
image_count = Math.max(1, Math.min(5, Math.floor(image_count)));

const supabase_url = String(
  pickFirst(wh.supabase_url, wh.supabaseUrl, 'https://supabase-api.atomx.top')
).trim().replace(/\/$/, '');

const supabase_api_key = String(
  pickFirst(wh.supabase_api_key, wh.supabaseApiKey, 'sb_secret_N7UND0UgjKTVK-Uodkm0Hg_xSvEMPvz')
).trim();

const supabase_bucket = String(
  pickFirst(wh.supabase_bucket, wh.supabaseBucket, 'uploads')
).trim();

const task_id = pickFirst(wh.task_id, wh.taskId, wh.id, null);
if (!task_id) {
  throw new Error('task_id is required (normalized input)');
}

return [{
  json: {
    task_id,
    api_key: pickFirst(wh.api_key, wh.apiKey, null),
    workflow_id: pickFirst(wh.workflow_id, wh.workflowId, 'flow_xhs_text2img'),
    workflow_name: pickFirst(wh.workflow_name, wh.workflowName, '图文排版生图'),
    title: toStringSafe(pickFirst(wh.title, wh.clean_title, '')),
    text: toStringSafe(pickFirst(wh.text, wh.content, '')),
    style_profile_json: toStringSafe(
      pickFirst(wh.style_profile_json, wh.style_json, wh['图文排版风格JSON'], '')
    ),
    image_count_user: image_count,

    supabase_url,
    supabase_api_key,
    supabase_bucket,

    raw_body: wh
  }
}];

function toText(v) {
  if (v == null) return '';
  if (Array.isArray(v)) {
    return v.map(x => {
      if (x == null) return '';
      if (typeof x === 'string') return x;
      if (typeof x === 'number') return String(x);
      if (typeof x === 'object' && x.text) return String(x.text);
      return '';
    }).join('');
  }
  if (typeof v === 'object' && v.text) return String(v.text);
  return String(v);
}

function extractJsonObjects(s) {
  s = String(s || '');
  const objs = [];
  let start = -1, depth = 0, inStr = false, esc = false;
  for (let i = 0; i < s.length; i++) {
    const ch = s[i];
    if (inStr) {
      if (esc) esc = false;
      else if (ch === '\\') esc = true;
      else if (ch === '"') inStr = false;
      continue;
    } else {
      if (ch === '"') { inStr = true; continue; }
    }
    if (ch === '{') {
      if (depth === 0) start = i;
      depth++;
    } else if (ch === '}') {
      depth--;
      if (depth === 0 && start >= 0) {
        objs.push(s.slice(start, i + 1));
        start = -1;
      }
    }
  }
  return objs;
}

function pickBestStyle(parsedList) {
  const scored = parsedList.map(o => {
    const styleName = o?.style_dna?.style_name ? 2 : 0;
    const hasPrompt = o?.generation_prompts?.prompt_text2img_universal ? 2 : 0;
    const hasLayout = o?.layout_blueprint?.modules ? 1 : 0;
    return { o, score: styleName + hasPrompt + hasLayout };
  }).sort((a,b) => b.score - a.score);
  return scored[0]?.o || null;
}

const item = $input.first().json || {};
let s = toText(item['图文排版风格JSON']).trim();

if (s.startsWith('[') && s.includes('"text"')) {
  try {
    const arr = JSON.parse(s);
    if (Array.isArray(arr)) {
      s = arr.map(x => (x && typeof x === 'object' && x.text) ? String(x.text) : '').join('').trim();
    }
  } catch (e) {}
}

const candidates = extractJsonObjects(s);
const parsed = [];
for (const c of candidates) {
  try { parsed.push(JSON.parse(c)); } catch (e) {}
}

const best = pickBestStyle(parsed);
let style_json_obj = best || { style_dna:{}, layout_blueprint:{}, generation_prompts:{}, content_mapping:{} };
let style_json_str = JSON.stringify(style_json_obj);

const sd = style_json_obj.style_dna || {};
const cs = sd.color_system || {};
const ty = sd.typography || {};
const ls = sd.layout_system || {};
const ic = sd.illustration_iconography || {};
const tx = sd.texture_and_background || {};

const style_summary = {
  style_name: sd.style_name || '',
  one_sentence_definition: sd.one_sentence_definition || '',
  colors: {
    background: cs.background || [],
    primary_text: cs.primary_text || [],
    secondary_text: cs.secondary_text || [],
    accent: cs.accent || [],
    highlight: cs.warning_or_highlight || [],
    rules: cs.color_usage_rules || []
  },
  typography: {
    title_font_vibe: ty.title_font_vibe || '',
    body_font_vibe: ty.body_font_vibe || '',
    hierarchy: ty.hierarchy || {},
    emphasis_methods: ty.emphasis_methods || []
  },
  layout: {
    grid: ls.grid || '',
    safe_margin: ls.safe_margin || '',
    module_spacing: ls.module_spacing || '',
    alignment: ls.alignment || '',
    density: ls.information_density || '',
    common_structures: ls.common_structures || []
  },
  iconography: {
    icon_style: ic.icon_style || '',
    stroke_weight: ic.stroke_weight || '',
    decorations: ic.decorations || [],
    chart_style: ic.chart_style || ''
  },
  texture: {
    background_texture: tx.background_texture || '',
    shadow_and_depth: tx.shadow_and_depth || ''
  },
  quality_bar: sd.quality_bar || [],
  module_visual_rules: (style_json_obj.layout_blueprint?.modules || []).flatMap(m => m.visual_rules || [])
};

return [{
  json: {
    ...item,
    style_json_obj,
    style_json_str,
    style_mode: 'summary',
    style_summary
  }
}];

options.systemMessage:
=你是“知识图文解说策划 + 多页知识卡分镜编辑”。

输入字段：
- title: 标题(string)
- text: 正文(string)
- style_json: 图文排版风格JSON(string，JSON或JSON字符串)

目标：
A) 先把正文整理成“知识解说型”结构：每个要点必须包含【结论一句】+【解释一句】（解释要具体，不要空话）
B) 图文张数由用户指定（image_count_user，1~5；若缺失/为空默认3）：
   - 你必须严格使用用户指定的张数，禁止自行增减。
   - image_plan.count 必须等于 image_count_user（默认3）
   - image_plan.images 数组长度必须等于 image_count_user，且 index 必须是 1..image_count_user 连续不缺号
   - 若正文太短，也必须按张数拆分：每张仍建议 3~5 条；实在不足可允许 2 条，但不得为 0 条
C) 明确排除互动/引导类内容，不做成图片：
   - 任何包含“留言/评论/私信/关注/点赞/转发/领取/加我/获取方案/找我/规划”等互动CTA句子，都归类为 interaction，只用于文案结尾，不进入 images。
D) 必须中文直出：所有 text_blocks 的中文必须精确渲染（不改字、不加字、不出现英文乱码）
E) 只输出严格 JSON，不要 markdown，不要解释

输出 JSON Schema（必须严格一致）：
{
  "content_plan": {
    "clean_title": "",
    "knowledge_sections": [
      {
        "section_title": "",
        "points": [
          { "point": "", "explain": "" }
        ]
      }
    ],
    "interaction_lines": ["..."]
  },
  "image_plan": {
    "aspect_ratio": "3:4",
    "count": 1,
    "reason": "",
    "images": [
      {
        "index": 1,
        "purpose": "cover|section|summary",
        "layout_hint": "知识解说图文（point+explain，两行结构）",
        "text_blocks": {
          "title": "",
          "subtitle": "",
          "items": [
            { "point": "", "explain": "" }
          ]
        },
        "prompt": "",
        "negative_prompt": ""
      }
    ]
  }
}

排版硬约束（必须遵守）：
- title <= 18字（可两行）
- 每张图 items 3~5条
- point <= 14字；explain <= 26字
- 禁止出现互动CTA在 items 里
- prompt 必须包含：EXACT Chinese text, sharp, high-contrast, print-like typography

