function stripFence(s) {
  return (s || '').replace(/```json\s*/i, '').replace(/```/g, '').trim();
}
function safeParse(s) { try { return JSON.parse(s); } catch { return null; } }
function asArray(v) { return Array.isArray(v) ? v : (v == null ? [] : [v]); }
function ensureTextBlocks(tb) {
  const out = tb && typeof tb === 'object' ? tb : {};
  if (!out.items && out.bullets) out.items = out.bullets;
  if (!Array.isArray(out.items)) out.items = [];
  out.title = (out.title ?? '').toString();
  out.subtitle = (out.subtitle ?? '').toString();
  return out;
}
function normalizeOneImage(img, indexFallback) {
  const o = img && typeof img === 'object' ? img : {};
  const idx = Number(o.index ?? indexFallback ?? 1) || 1;
  const tb = ensureTextBlocks(o.text_blocks);
  tb.items = tb.items.map(it => {
    if (!it || typeof it !== 'object') return { point: '', explain: '' };
    return {
      point: (it.point ?? it.text ?? it.name ?? '').toString().trim(),
      explain: (it.explain ?? it.caption ?? it.desc ?? '').toString().trim()
    };
  }).filter(x => x.point || x.explain);
  return {
    index: idx,
    purpose: (o.purpose ?? '').toString() || (idx === 1 ? 'cover' : 'section'),
    layout_hint: (o.layout_hint ?? '知识解说图文（point+explain，两行结构）').toString(),
    text_blocks: tb,
    prompt: (o.prompt ?? '').toString(),
    negative_prompt: (o.negative_prompt ?? '').toString()
  };
}

const raw = $json.output;
if (!raw) throw new Error('缺少 output（内容梳理节点没有输出）');
const cleaned = stripFence(String(raw));
const obj = safeParse(cleaned);
if (!obj || typeof obj !== 'object') {
  throw new Error('内容梳理 output 不是合法 JSON');
}

const merged = { ...$json, ...obj };
if (!merged.content_plan || typeof merged.content_plan !== 'object') {
  merged.content_plan = { clean_title: '', knowledge_sections: [], interaction_lines: [] };
}
if (!merged.image_plan || typeof merged.image_plan !== 'object') {
  merged.image_plan = { aspect_ratio: '3:4', count: 3, reason: '', images: [] };
}

const plan = merged.image_plan;
plan.aspect_ratio = (plan.aspect_ratio ?? '3:4').toString().trim() || '3:4';
plan.reason = (plan.reason ?? '').toString();
plan.images = asArray(plan.images).map((img, i) => normalizeOneImage(img, i + 1));

let userCount = Number(merged.image_count_user ?? merged.user_image_count);
if (!Number.isFinite(userCount) || userCount < 1) userCount = 3;
userCount = Math.max(1, Math.min(5, Math.floor(userCount)));
plan.count = userCount;

plan.images.sort((a, b) => Number(a.index) - Number(b.index));
const byIndex = new Map();
for (const im of plan.images) {
  const idx = Number(im.index);
  if (!byIndex.has(idx)) byIndex.set(idx, im);
}

const filled = [];
for (let i = 1; i <= userCount; i++) {
  if (byIndex.has(i)) {
    const im = byIndex.get(i);
    im.index = i;
    filled.push(im);
    continue;
  }
  filled.push(normalizeOneImage({
    index: i,
    purpose: i === 1 ? 'cover' : 'section',
    layout_hint: '知识解说图文（point+explain，两行结构）',
    text_blocks: {
      title: i === 1 ? (merged.content_plan?.clean_title || merged.title || '') : '',
      subtitle: '',
      items: []
    },
    prompt: 'EXACT Chinese text, sharp, high-contrast, print-like typography.',
    negative_prompt: ''
  }, i));
}

const sections = asArray(merged.content_plan?.knowledge_sections);
const allPoints = sections.flatMap(s => asArray(s?.points)).map(p => ({
  point: (p?.point ?? '').toString().trim(),
  explain: (p?.explain ?? '').toString().trim()
})).filter(x => x.point || x.explain);

const perPage = Math.max(2, Math.min(5, Math.ceil(allPoints.length / Math.max(1, userCount))));
let cursor = 0;
for (const im of filled) {
  const items = asArray(im.text_blocks?.items);
  if (items.length >= 2) continue;
  const slice = allPoints.slice(cursor, cursor + perPage);
  if (slice.length) {
    im.text_blocks.items = slice.slice(0, 5);
    cursor += slice.length;
  }
}

plan.images = filled;
if (!plan.reason) plan.reason = `按用户指定张数 ${userCount} 张输出（未填默认3）。`;

return [{ json: merged }];

function s(v){ return v == null ? '' : String(v); }
function asArray(v){ return Array.isArray(v) ? v : (v == null ? [] : [v]); }

const root = $input.first().json || {};
const imagePlan = root.image_plan || {};
const images = asArray(imagePlan.images);
if (!images.length) throw new Error('image_plan.images 为空');

const style_json_obj = (root.style_json_obj && typeof root.style_json_obj === 'object') ? root.style_json_obj : null;
const style_json_str = s(root.style_json_str);
const aspect_ratio = s(imagePlan.aspect_ratio || '3:4').trim() || '3:4';

let user_image_count = Number(root.image_count_user ?? imagePlan.count);
if (!Number.isFinite(user_image_count) || user_image_count < 1) user_image_count = 3;
user_image_count = Math.max(1, Math.min(5, Math.floor(user_image_count)));

const out = images.map((img, idx) => {
  const o = (img && typeof img === 'object') ? img : {};
  const image_index = Number(o.index ?? (idx + 1)) || (idx + 1);
  const text_blocks = o.text_blocks && typeof o.text_blocks === 'object' ? o.text_blocks : { title: '', subtitle: '', items: [] };
  return {
    json: {
      ...root,
      user_image_count,
      aspect_ratio,
      image_index,
      purpose: s(o.purpose || 'section'),
      layout_hint: s(o.layout_hint),
      text_blocks,
      prompt_base: s(o.prompt).trim(),
      negative_prompt: s(o.negative_prompt).trim(),
      style_json_obj,
      style_json_str
    }
  };
});

for (const item of out) {
  delete item.json.image_plan;
  delete item.json.content_plan;
  delete item.json.output;
}
return out;

function s(v){ return v == null ? '' : String(v); }
function asArray(v){ return Array.isArray(v) ? v : (v == null ? [] : [v]); }
const GLOBAL_STYLE_MODE = 'summary';

function normalizeBlocks(tb){
  const o = tb && typeof tb === 'object' ? tb : {};
  const items = asArray(o.items).map(x => ({
    point: s(x?.point).trim(),
    explain: s(x?.explain).trim(),
  })).filter(x => x.point || x.explain);
  return {
    title: s(o.title).trim(),
    subtitle: s(o.subtitle).trim(),
    items,
  };
}

function buildExactTextBlock(tb){
  const lines = [];
  lines.push('[EXACT_TEXT_BLOCKS]');
  lines.push(`TITLE: "${tb.title}"`);
  if (tb.subtitle) lines.push(`SUBTITLE: "${tb.subtitle}"`);
  tb.items.forEach((it, idx) => {
    const i = idx + 1;
    lines.push(`POINT_${i}: "${it.point}"`);
    lines.push(`EXPLAIN_${i}: "${it.explain}"`);
  });
  lines.push('[/EXACT_TEXT_BLOCKS]');
  return lines.join('\n');
}

function pickStyleSummary(styleObj){
  const dna = styleObj?.style_dna || {};
  const cs = dna?.color_system || {};
  const typo = dna?.typography || {};
  const layout = dna?.layout_system || {};
  const icon = dna?.illustration_iconography || {};
  const tex = dna?.texture_and_background || {};
  const moduleRules = asArray(styleObj?.layout_blueprint?.modules)
    .flatMap(m => asArray(m?.visual_rules).map(r => s(r).trim()))
    .filter(Boolean);
  return {
    style_name: s(dna.style_name).trim(),
    one_sentence_definition: s(dna.one_sentence_definition).trim(),
    colors: {
      background: asArray(cs.background).slice(0, 3),
      primary_text: asArray(cs.primary_text).slice(0, 2),
      secondary_text: asArray(cs.secondary_text).slice(0, 2),
      accent: asArray(cs.accent).slice(0, 6),
      highlight: asArray(cs.warning_or_highlight).slice(0, 3),
      rules: asArray(cs.color_usage_rules).slice(0, 6),
    },
    typography: {
      title_font_vibe: s(typo.title_font_vibe).trim(),
      body_font_vibe: s(typo.body_font_vibe).trim(),
      hierarchy: typo.hierarchy || {},
      emphasis_methods: asArray(typo.emphasis_methods).slice(0, 6),
    },
    layout: {
      grid: s(layout.grid).trim(),
      safe_margin: s(layout.safe_margin).trim(),
      module_spacing: s(layout.module_spacing).trim(),
      alignment: s(layout.alignment).trim(),
      density: s(layout.information_density).trim(),
      common_structures: asArray(layout.common_structures).slice(0, 3),
    },
    iconography: {
      icon_style: s(icon.icon_style).trim(),
      stroke_weight: s(icon.stroke_weight).trim(),
      decorations: asArray(icon.decorations).slice(0, 6),
      chart_style: s(icon.chart_style).trim(),
    },
    texture: {
      background_texture: s(tex.background_texture).trim(),
      shadow_and_depth: s(tex.shadow_and_depth).trim(),
    },
    quality_bar: asArray(dna.quality_bar).slice(0, 6),
    module_visual_rules: moduleRules.slice(0, 10),
  };
}

function buildStyleBlock(styleMode, styleObj){
  if (!styleObj || typeof styleObj !== 'object') return '';
  if (styleMode === 'off') return '';
  const st = pickStyleSummary(styleObj);
  const lines = [];
  lines.push('[STYLE_GUIDE]');
  if (st.style_name) lines.push(`style_name: ${st.style_name}`);
  if (st.one_sentence_definition) lines.push(`definition: ${st.one_sentence_definition}`);
  const c = st.colors || {};
  if (c.background?.length) lines.push(`background_colors: ${c.background.join(', ')}`);
  if (c.primary_text?.length) lines.push(`primary_text_colors: ${c.primary_text.join(', ')}`);
  if (c.secondary_text?.length) lines.push(`secondary_text_colors: ${c.secondary_text.join(', ')}`);
  if (c.accent?.length) lines.push(`accent_colors: ${c.accent.join(', ')}`);
  if (c.highlight?.length) lines.push(`highlight_colors: ${c.highlight.join(', ')}`);
  if (c.rules?.length) lines.push(`color_usage_rules: ${c.rules.join(' | ')}`);
  const t = st.typography || {};
  if (t.title_font_vibe) lines.push(`title_font_vibe: ${t.title_font_vibe}`);
  if (t.body_font_vibe) lines.push(`body_font_vibe: ${t.body_font_vibe}`);
  if (t.emphasis_methods?.length) lines.push(`emphasis_methods: ${t.emphasis_methods.join(' | ')}`);
  const l = st.layout || {};
  if (l.grid) lines.push(`layout_grid: ${l.grid}`);
  if (l.safe_margin) lines.push(`safe_margin: ${l.safe_margin}`);
  if (l.module_spacing) lines.push(`module_spacing: ${l.module_spacing}`);
  if (l.alignment) lines.push(`alignment: ${l.alignment}`);
  if (l.density) lines.push(`information_density: ${l.density}`);
  if (l.common_structures?.length) lines.push(`common_structures: ${l.common_structures.join(' | ')}`);
  const ic = st.iconography || {};
  if (ic.icon_style) lines.push(`icon_style: ${ic.icon_style}`);
  if (ic.stroke_weight) lines.push(`stroke_weight: ${ic.stroke_weight}`);
  if (ic.decorations?.length) lines.push(`decorations: ${ic.decorations.join(' | ')}`);
  if (ic.chart_style) lines.push(`chart_style: ${ic.chart_style}`);
  const tx = st.texture || {};
  if (tx.background_texture) lines.push(`background_texture: ${tx.background_texture}`);
  if (tx.shadow_and_depth) lines.push(`shadow_and_depth: ${tx.shadow_and_depth}`);
  if (st.quality_bar?.length) lines.push(`quality_bar: ${st.quality_bar.join(' | ')}`);
  if (st.module_visual_rules?.length) lines.push(`module_visual_rules: ${st.module_visual_rules.join(' | ')}`);
  lines.push('[/STYLE_GUIDE]');
  return lines.join('\n');
}

function buildTextRules(){
  return [
    'Render EXACT Chinese text as provided. Do NOT change any character.',
    'Do NOT add extra text. No English letters, no pinyin, no random symbols.',
    'Text must be sharp, high-contrast, clean edges; legible on mobile; no blur; no broken strokes.',
    'Keep generous margins and spacing; do not crowd text; no overlapping.',
    'Each item uses two-line structure: point (short) + explain (one sentence).',
  ].join(' ');
}

function buildPrompt({ promptBase, tb, styleBlock, layoutHint }){
  const avoid = 'Avoid: wrong Chinese characters, missing strokes, extra text, English letters, garbled words, watermark, low resolution, cluttered layout, overlapping text, distorted characters, messy.';
  const exact = buildExactTextBlock(tb);
  const base = s(promptBase).trim();
  return [
    base || '',
    buildTextRules(),
    layoutHint ? `Layout hint: ${layoutHint}` : '',
    styleBlock || '',
    avoid,
    '',
    exact
  ].filter(Boolean).join('\n\n');
}

function buildNegativePrompt(styleObj, userNeg){
  const baseNeg = s(styleObj?.generation_prompts?.negative_prompt || '').trim();
  const extraNeg = s(userNeg).trim();
  return [baseNeg, extraNeg].filter(Boolean).join(', ');
}

function buildRequestBody({ aspectRatio, promptText, negativePrompt }){
  const ratioHintMap = {
    '3:4': 'portrait 3:4 layout, vertical knowledge poster',
    '4:5': 'portrait 4:5 layout, vertical knowledge poster',
    '1:1': 'square layout',
    '16:9': 'landscape 16:9 layout',
    '9:16': 'vertical 9:16 layout'
  };

  const ratioHint = ratioHintMap[aspectRatio] || `layout ratio ${aspectRatio}`;

  const finalPrompt = [
    promptText,
    '',
    '[LAYOUT_RATIO]',
    ratioHint,
    negativePrompt ? '' : null,
    negativePrompt ? '[NEGATIVE_PROMPT]' : null,
    negativePrompt || null
  ].filter(v => v !== null && v !== '').join('\n');

  return {
    contents: [
      {
        role: 'user',
        parts: [
          {
            text: finalPrompt
          }
        ]
      }
    ],
    generationConfig: {
      responseModalities: ['IMAGE']
    }
  };
}

const items = $input.all();
if (!items.length) throw new Error('没有输入数据');

const normalized = items.map((it) => {
  const j = it.json || {};
  const aspect_ratio = s(j.aspect_ratio || '3:4').trim() || '3:4';
  const image_index = Number(j.image_index || j.index || 1) || 1;
  const layout_hint = s(j.layout_hint).trim();
  const purpose = s(j.purpose || 'section').trim();
  const tb = normalizeBlocks(j.text_blocks);
  const style_mode = s(j.style_mode || GLOBAL_STYLE_MODE).trim() || GLOBAL_STYLE_MODE;
  const styleObj = (j.style_json_obj && typeof j.style_json_obj === 'object') ? j.style_json_obj : null;
  const styleBlock = buildStyleBlock(style_mode, styleObj);
  const promptText = buildPrompt({ promptBase: j.prompt_base, tb, styleBlock, layoutHint: layout_hint });
  const negativePrompt = buildNegativePrompt(styleObj, j.negative_prompt);
  const request_body = buildRequestBody({ aspectRatio: aspect_ratio, promptText, negativePrompt });

  return {
    ...j,
    aspect_ratio,
    image_index,
    purpose,
    layout_hint,
    text_blocks: tb,
    style_mode,
    style_summary: styleObj ? pickStyleSummary(styleObj) : null,
    request_body
  };
});

function hashForDedup(x){
  const tb = x.text_blocks || {};
  const key = {
    title: tb.title,
    subtitle: tb.subtitle,
    items: (tb.items || []).map(i => [i.point, i.explain]),
    aspect_ratio: x.aspect_ratio,
    layout_hint: x.layout_hint,
    style_name: x.style_summary?.style_name || ''
  };
  return JSON.stringify(key);
}

const seen = new Map();
const deduped = [];
for (const x of normalized) {
  const h = hashForDedup(x);
  if (!seen.has(h)) {
    seen.set(h, x.image_index);
    deduped.push(x);
  } else {
    const keptIndex = seen.get(h);
    if (x.image_index < keptIndex) {
      const idx = deduped.findIndex(d => hashForDedup(d) === h);
      if (idx >= 0) deduped[idx] = x;
      seen.set(h, x.image_index);
    }
  }
}

deduped.sort((a,b)=> (a.image_index||0) - (b.image_index||0));
return deduped.map(x => ({ json: x }));

function unwrapRoot(x) {
  if (x && typeof x === 'object' && x.body && typeof x.body === 'object') return x.body;
  return x;
}

function stripDataPrefix(b64) {
  return String(b64 || '').replace(/^data:.*;base64,/, '').trim();
}

function findInlineImageParts(root) {
  const candidates = root?.candidates;
  if (!Array.isArray(candidates) || !candidates.length) return [];

  const imgs = [];
  for (const c of candidates) {
    const parts = c?.content?.parts;
    if (!Array.isArray(parts)) continue;

    for (const p of parts) {
      const inline = p?.inline_data || p?.inlineData;
      if (inline?.data) {
        imgs.push({
          b64: inline.data,
          mimeType: inline.mime_type || inline.mimeType || 'image/png'
        });
      }
    }
  }
  return imgs;
}

const items = $input.all();
const output = [];

for (let itemIndex = 0; itemIndex < items.length; itemIndex++) {
  const raw = items[itemIndex].json || {};
  const root = unwrapRoot(raw);
  const imgs = findInlineImageParts(root);

  if (!imgs.length) continue;

  for (let i = 0; i < imgs.length; i++) {
    const img = imgs[i];
    const mimeType = img.mimeType || 'image/png';
    const ext = /jpe?g/i.test(mimeType) ? 'jpg' : 'png';
    const b64 = stripDataPrefix(img.b64);

    if (!b64) continue;

    const globalIndex = output.length + 1;
    const localIndex = i + 1;

    output.push({
      json: {
        ...raw,
        task_id: raw.task_id || raw.taskId || '',
        image_upload_url: raw.image_upload_url || '',
        admin_token: raw.admin_token || '',
        image_index: globalIndex,
        image_payload: {
          global_index: globalIndex,
          local_index: localIndex,
          source_item_index: itemIndex + 1,
          mimeType,
          fileName: `knowledge_card_${globalIndex}.${ext}`,
          base64: b64
        }
      }
    });
  }
}

if (!output.length) {
  throw new Error('没有在任何输入项中找到图片 base64');
}

return output;

const items = $input.all();
if (!items.length) {
  throw new Error('没有可聚合的 OSS 图片结果');
}

const first = items[0].json || {};
const images = items
  .map(it => {
    const j = it.json || {};
    return {
      index: Number(j.image_index || 0) || 0,
      url: j.publicUrl || '',
      fileName: j.fileName || '',
      mimeType: j.mimeType || ''
    };
  })
  .filter(x => x.url)
  .sort((a, b) => a.index - b.index);

if (!images.length) {
  throw new Error('publicUrl 为空，无法生成图片 URL 数组');
}

return [{
  json: {
    ...first,
    generated_images_json: JSON.stringify(images),
    layout_result_json: JSON.stringify({
      content_plan: first.content_plan || {},
      image_plan: first.image_plan || {}
    })
  }
}];

const item = $input.item;
const j = item.json || {};

function pickFirst(...vals) {
  for (const v of vals) {
    if (v !== undefined && v !== null && String(v).trim() !== '') return v;
  }
  return '';
}

function normalizeBase64(v) {
  const s = String(v || '').trim();
  if (!s) return '';
  const m = s.match(/^data:[^;]+;base64,(.+)$/);
  return m ? m[1] : s;
}

const taskId = pickFirst(j.task_id, j.taskId, $('标准化输入').first().json.task_id);
const imagePayload = j.image_payload || {};

const rawBase64 = pickFirst(
  imagePayload.base64,
  j.base64
);
const base64 = normalizeBase64(rawBase64);

const mimeType = pickFirst(
  j.mimeType,
  imagePayload.mimeType,
  'image/png'
);

const fileName = pickFirst(
  j.fileName,
  imagePayload.fileName,
  `image_${Number(j.image_index || 0)}.png`
);

const imageIndex = Number(j.image_index || 0);

const supabaseUrl = String(pickFirst(j.supabase_url, j.supabaseUrl, $('标准化输入').first().json.supabase_url)).trim().replace(/\/+$/, '');
const supabaseApiKey = String(pickFirst(j.supabase_api_key, j.supabaseApiKey, $('标准化输入').first().json.supabase_api_key)).trim();
const supabaseBucket = String(pickFirst(j.supabase_bucket, j.supabaseBucket, $('标准化输入').first().json.supabase_bucket, 'uploads')).trim();

if (!taskId) {
  throw new Error('task_id is required for upload');
}
if (!base64) {
  throw new Error('No base64 image data to upload');
}
if (!supabaseUrl) {
  throw new Error('supabase_url not provided');
}
if (!supabaseApiKey) {
  throw new Error('supabase_api_key not provided');
}
if (!supabaseBucket) {
  throw new Error('supabase_bucket not provided');
}

const uploadUrl = `${supabaseUrl}/storage/v1/object/${supabaseBucket}/${taskId}/${fileName}`;

const fileBuffer = Buffer.from(base64, 'base64');

const response = await $helpers.httpRequest({
  method: 'POST',
  url: uploadUrl,
  headers: {
    Authorization: `Bearer ${supabaseApiKey}`,
    apikey: supabaseApiKey,
    'Content-Type': mimeType,
    'x-upsert': 'true',
  },
  body: fileBuffer,
  encoding: null,
  json: false,
});

const publicUrl = `${supabaseUrl}/storage/v1/object/public/${supabaseBucket}/${taskId}/${fileName}`;

return {
  json: {
    ...j,
    publicUrl,
    supabasePath: `${taskId}/${fileName}`,
    image_index: imageIndex,
    fileName,
    mimeType,
    uploadResponse: response ?? null
  }
};
